// Helper function to get the mirror character
fn get_mirror(c: char) -> char {
    if c.is_ascii_lowercase() {
        // Letter mirroring: 'a' <-> 'z', 'b' <-> 'y', etc.
        let offset = (c as u8) - (b'a');
        let mirror_offset = 25 - offset;
        return (b'a' + mirror_offset as u8) as char;
    } else if c.is_ascii_digit() {
        // Digit mirroring: '0' <-> '9', '1' <-> '8', etc.
        let digit_value = (c as u8) - (b'0');
        let mirror_value = 9 - digit_value;
        return (b'0' + mirror_value as u8) as char;
    }
    // Should not happen based on constraints
    c
}

// Helper structure/key for storing processed pairs (to ensure (c, m) and (m, c) are counted once)
// Since chars are comparable, we can use a tuple or string concatenation for the key.
// Using a tuple of chars is safer if the environment supports it well.
// Assuming a standard map implementation where tuple keys work, or converting to a comparable string.

// Since we need to use it as a key in a set/map, and chars are basic types, we use a representation that is hashable/comparable.
// We will use a tuple representation internally for logic, relying on the map key structure.

func solve(s: String) -> Int64 {
    // 1. Calculate frequencies
    let mut freq_map: HashMap<char, Int64> = HashMap::new();
    for c in s.chars() {
        *freq_map.entry(c).or_insert(0) += 1;
    }

    let unique_chars: Vec<char> = freq_map.keys().cloned().collect();

    // Set to track pairs already processed: stores canonical pair (min_char, max_char)
    let mut processed_pairs: HashMap<(char, char), bool> = HashMap::new();

    let mut total_difference: Int64 = 0;

    // 2. Iterate over unique characters found in s
    for c in unique_chars {
        let m = get_mirror(c);

        // Determine the canonical representation of the pair (c, m)
        let canonical_pair = if c < m {
            (c, m)
        } else {
            (m, c)
        };

        // 3. Check if this pair has already been processed
        if processed_pairs.contains_key(&canonical_pair) {
            continue;
        }

        // Mark as processed immediately
        processed_pairs.insert(canonical_pair, true);

        // 4. Get frequencies (defaulting to 0 if the mirror character is not in s)
        let freq_c = freq_map.get(&c).unwrap_or(&0);
        let freq_m = freq_map.get(&m).unwrap_or(&0);

        // 5. Calculate absolute difference and add to total
